const AUTH_STORAGE_KEY="dls_auth_v1";function getCurrentSession(){const e=localStorage.getItem("dls_auth_v1");if(!e)return null;try{return JSON.parse(e)}catch(e){return localStorage.removeItem("dls_auth_v1"),null}}function setCurrentSession(e){localStorage.setItem("dls_auth_v1",JSON.stringify(e))}function clearCurrentSession(){localStorage.removeItem("dls_auth_v1")}function pathEndsWith(e){return window.location.pathname.toLowerCase().endsWith(e.toLowerCase())}const Auth={getSession:()=>getCurrentSession(),isLoggedIn:()=>Boolean(getCurrentSession()),hasRole(e){const t=getCurrentSession();return Boolean(t&&t.user&&t.user.role===e)},async syncSession(){try{const e=await Api.getSession();return setCurrentSession(e),e}catch(e){return clearCurrentSession(),null}},async login(e,t){const n=await Api.login(e,t);return setCurrentSession(n),n},async register(e,t,n,r,o){const l=await Api.register({fullName:e,username:t,password:n,role:r,librarianPin:o});return setCurrentSession(l),l},async logout(){const e=getCurrentSession();try{await Api.logout(e?e.token:null)}catch(e){}finally{clearCurrentSession(),window.location.href="index.html"}},redirectByRole(){const e=getCurrentSession();e?"admin"!==e.user.role?"librarian"!==e.user.role?window.location.href="patron-dashboard.html":window.location.href="librarian-dashboard.html":window.location.href="admin-log.html":window.location.href="index.html"},requireAuth(e=[]){const t=getCurrentSession();return t?e.length>0&&!e.includes(t.user.role)?(this.redirectByRole(),null):t:(window.location.href="index.html",null)},buildNav(e){const t=getCurrentSession(),n=document.getElementById(e);if(!n||!t)return;for(;n.firstChild;)n.removeChild(n.firstChild);[{role:"all",href:"catalog.html",label:"Catalog"},{role:"patron",href:"patron-dashboard.html",label:"Borrowing"},{role:"librarian",href:"librarian-dashboard.html",label:"Librarian Home"},{role:"librarian",href:"inventory.html",label:"Inventory"},{role:"librarian",href:"transactions.html",label:"Transactions"},{role:"admin",href:"admin-log.html",label:"System Log"}].forEach(e=>{if("all"!==e.role&&e.role!==t.user.role)return;const r=document.createElement("a");r.href=e.href,r.className="nav-link",r.textContent=e.label,pathEndsWith(e.href)&&r.classList.add("active"),n.appendChild(r)});const r=document.createElement("span");r.className="nav-link",r.textContent=`${t.user.fullName} (${t.user.role})`,n.appendChild(r);const o=document.createElement("button");o.type="button",o.className="nav-button",o.textContent="Logout",o.addEventListener("click",()=>this.logout()),n.appendChild(o)}};
